def generate_tone(frequency, duration, sample_rate=44100, volume=0.6):
    """Generate a sine wave tone as pygame sound."""
    t = np.linspace(0, duration, int(sample_rate * duration), endpoint=False)
    # Add harmonics for richer sound
    wave = (np.sin(2 * np.pi * frequency * t) * 0.6 +
            np.sin(2 * np.pi * frequency * 2 * t) * 0.2 +
            np.sin(2 * np.pi * frequency * 3 * t) * 0.1)
    # Envelope: attack, sustain, release
    attack = int(0.05 * sample_rate)
    release = int(0.15 * sample_rate)
    envelope = np.ones(len(t))
    if attack > 0:
        envelope[:attack] = np.linspace(0, 1, attack)
    if release > 0 and release < len(t):
        envelope[-release:] = np.linspace(1, 0, release)
    wave = wave * envelope * volume
    # Convert to int16 stereo
    wave_int = (wave * 32767).astype(np.int16)
    stereo = np.column_stack([wave_int, wave_int])
    return pygame.sndarray.make_sound(stereo)


