def play_note(idx):
    """Play a note and activate its column."""
    global current_note
    current_note = idx
    sounds[idx].play()
    columns[idx].activate()
    # Scatter nearby stars
    for star in stars:
        star.scatter(columns[idx].x, HEIGHT - 50, strength=4)
    print(f"  Playing note {idx + 1}/5: {NOTE_NAMES[idx]} ({NOTE_FREQS[idx]:.1f} Hz)")


# Background surface for stars (pre-render once, update each frame)
bg_surf = pygame.Surface((WIDTH, HEIGHT))
bg_surf.fill(BLACK)

time_elapsed = 0
running = True

print("Starting 'First Contact' experience...")
print("Click the central button to play the five-note motif!")

while running:
    dt = clock.tick(FPS) / 1000.0
    time_elapsed += dt

    # Events
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        elif event.type == pygame.KEYDOWN:
            if event.key == pygame.K_ESCAPE:
                running = False
            elif event.key == pygame.K_SPACE and not playing:
                playing = True
                note_index = 0
                note_timer = 0
                sequence_complete = False
                print("\nStarting five-note sequence...")
                play_note(0)
                note_timer = NOTE_DURATIONS[0]
        elif event.type == pygame.MOUSEBUTTONDOWN:
            if event.button == 1 and not playing:
                if button.is_clicked(event.pos):
                    playing = True
                    note_index = 0
                    note_timer = 0
                    sequence_complete = False
                    print("\nStarting five-note sequence...")
                    play_note(0)
                    note_timer = NOTE_DURATIONS[0]

    # Update sequence
    if playing:
        note_timer -= dt
        if note_timer <= 0:
            # Deactivate current column
            if current_note >= 0:
                columns[current_note].active = False
            note_index += 1
            if note_index < 5:
                play_note(note_index)
                note_timer = NOTE_DURATIONS[note_index]
            else:
                playing = False
                current_note = -1
                sequence_complete = True
                sequence_delay = 3.0
                print("Sequence complete!")

    if sequence_complete:
        sequence_delay -= dt
        if sequence_delay <= 0:
            sequence_complete = False

    # Update objects
    for star in stars:
        star.update(time_elapsed)
    for col in columns:
        col.update()
    scanner.update()
    button.update(time_elapsed)

    # Update alien symbols
    for sym in alien_symbols:
        sym.update()
        if not sym.active:
            sym.reset()

    # Occasionally spawn new symbols
    if random.random() < 0.005:
        alien_symbols.append(AlienSymbol())
        if len(alien_symbols) > 15:
            alien_symbols.pop(0)

    for mist in mist_particles:
        mist.update()

    # Draw
    screen.fill(BLACK)

    # Draw stars
    for star in stars:
        star.draw(screen)

    # Draw mist
    for mist in mist_particles:
        mist.draw(screen)

    # Draw scanner
    scanner.draw(screen)

    # Horizon line
    horizon_y = HEIGHT - 90
    pygame.draw.line(screen, (20, 40, 60), (0, horizon_y), (WIDTH, horizon_y), 1)
    # Ground glow
    ground_surf = pygame.Surface((WIDTH, 90), pygame.SRCALPHA)
    for i in range(90):
        t = i / 90
        a = int(40 * (1 - t))
        pygame.draw.line(ground_surf, (20, 50, 80, a), (0, i), (WIDTH, i))
    screen.blit(ground_surf, (0, horizon_y))

    # Draw alien symbols
    for sym in alien_symbols:
        sym.draw(screen)

    # Draw columns
    for col in columns:
        col.draw(screen)

    # Draw column labels
    for i, col in enumerate(columns):
        if col.height > 10:
            label = note_font.render(NOTE_NAMES[i], True, NOTE_COLORS[i])
            screen.blit(label, (int(col.x) - label.get_width() // 2, HEIGHT - 85))

    # Draw button (only when not playing)
    if not playing:
        button.draw(screen)

    # Title
    title_surf = title_font.render("FIRST CONTACT", True, (200, 180, 120))
    # Add subtle glow
    glow_title = title_font.render("FIRST CONTACT", True, (100, 80, 40))
    screen.blit(glow_title, (WIDTH // 2 - title_surf.get_width() // 2 + 2, 32))
    screen.blit(title_surf, (WIDTH // 2 - title_surf.get_width() // 2, 30))

    subtitle_text = "The Five-Note Motif from Close Encounters of the Third Kind"
    sub_surf = subtitle_font.render(subtitle_text, True, (120, 110, 80))
    screen.blit(sub_surf, (WIDTH // 2 - sub_surf.get_width() // 2, 75))

    # Instructions
    if not playing:
        inst_font = pygame.font.SysFont('Arial', 15)
        inst = inst_font.render("Click the button or press SPACE to begin | ESC to quit", True, (80, 80, 100))
        screen.blit(inst, (WIDTH // 2 - inst.get_width() // 2, HEIGHT - 30))

    # Playing indicator
    if playing and current_note >= 0:
        note_display = note_font.render(
            f"Note {current_note + 1}/5: {NOTE_NAMES[current_note]}  ({NOTE_FREQS[current_note]:.0f} Hz)",
            True, NOTE_COLORS[current_note]
        )
        screen.blit(note_display, (WIDTH // 2 - note_display.get_width() // 2, HEIGHT - 30))

    # Sequence complete message
    if sequence_complete:
        complete_font = pygame.font.SysFont('Arial', 28, bold=True)
        msg = complete_font.render("They are here...", True, (180, 220, 255))
        alpha_val = min(255, int(255 * (sequence_delay / 3.0 if sequence_delay < 1.5 else 1.0)))
        msg.set_alpha(alpha_val)
        screen.blit(msg, (WIDTH // 2 - msg.get_width() // 2, HEIGHT // 2 - 20))

    pygame.display.flip()

pygame.quit()
sys.exit()